mapper.select:
SELECT city, bungi, bonBun, buBun, dangi, gubun, dediArea, contYear, contDate, deposit, monPay, floor, consYear, road, term, termGubun, rightRequ, prevDeposit, prevMonPay, housKind, sido, sigungu, dong FROM KR_REAL_RENT_INFO WHERE 1 = 1
AND sido = #{sido}
AND sigungu = #{sigungu}
AND dong = #{dong}
AND ContYear BETWEEN CONCAT(#{year}, '01') AND CONCAT(#{year}, '12')
AND Gubun = #{gubun}
ORDER BY ContYear DESC, ContDate DESC

SELECT
    ContYear AS contYear,
    COUNT(ContYear) AS cnt
FROM KR_REAL_RENT_INFO
WHERE sido = #{sido}


    AND sigungu = #{sigungu}



    AND dong = #{dong}

AND ContYear BETWEEN #{startYearMonth} AND #{endYearMonth}
GROUP BY ContYear
ORDER BY ContYear ASC
